from lxml import etree
import io

def process_soap_request(xml_content):
    # Enable DTD validation
    parser = etree.XMLParser(dtd_validation=True, load_dtd=True, no_network=False)
    
    try:
        # Parse the XML with DTD validation
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Check if it's a SOAP envelope
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    envelope = root.find(f".//{{{soap_namespace}}}Envelope")
    
    if envelope is None:
        raise ValueError("Not a valid SOAP envelope")
    
    # Extract the body
    body = envelope.find(f".//{{{soap_namespace}}}Body")
    
    if body is None:
        raise ValueError("SOAP envelope missing body")
    
    # Return the raw XML of the body
    return etree.tostring(body, encoding='unicode', pretty_print=True)

def process_soap_request_with_schema(xml_content, schema_file=None):
    # Parse with DTD validation
    parser = etree.XMLParser(dtd_validation=True, load_dtd=True, no_network=False)
    
    try:
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    # Check for SOAP envelope
    soap_namespace = "http://schemas.xmlsoap.org/soap/envelope/"
    envelope = root.find(f".//{{{soap_namespace}}}Envelope")
    
    if envelope is None:
        raise ValueError("Not a valid SOAP envelope")
    
    # Extract the body
    body = envelope.find(f".//{{{soap_namespace}}}Body")
    
    if body is None:
        raise ValueError("SOAP envelope missing body")
    
    # If schema is provided, validate against it
    if schema_file:
        try:
            with open(schema_file, 'r') as f:
                schema_doc = etree.parse(f)
                schema = etree.XMLSchema(schema_doc)
                schema.validate(root)
        except Exception as e:
            raise ValueError(f"Schema validation failed: {e}")
    
    # Return body content
    body_content = {}
    for child in body:
        body_content[child.tag] = etree.tostring(child, encoding='unicode', pretty_print=True)
    
    return body_content